// Helper: HTTP Request が string で返した場合は JSON.parse して正規化 (sync test 2026-05-07)
function normalize(item) {
  if (item && item.json && typeof item.json.data === 'string') {
    try {
      return { json: JSON.parse(item.json.data) };
    } catch (e) {
      return item;
    }
  }
  return item;
}

const now = new Date().toISOString();

// --- Build stats lookup by campaign_id ---
const statsItems = $('HTTP: Klaviyo Campaign Values Report').all().map(normalize);
const statsByCampaign = {};
for (const item of statsItems) {
  const results = (item.json && item.json.data && item.json.data.attributes && item.json.data.attributes.results) || [];
  for (const r of results) {
    const cid = r.groupings && r.groupings.campaign_id;
    if (cid) statsByCampaign[cid] = r.statistics || {};
  }
}

// --- Iterate campaign metadata items ---
const rows = [];
for (const rawItem of $('HTTP: Klaviyo Campaigns Metadata').all()) {
  const item = normalize(rawItem);
  const campaigns = (item.json && Array.isArray(item.json.data)) ? item.json.data : [];
  for (const c of campaigns) {
    const attrs = c.attributes || {};
    const stats = statsByCampaign[c.id] || {};
    const sentAt = attrs.send_time || attrs.scheduled_at || null;
    let dow = null, hour = null;
    if (sentAt) {
      const d = new Date(sentAt);
      dow = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'][d.getUTCDay()];
      hour = d.getUTCHours();
    }
    rows.push({
      campaign_id: c.id,
      campaign_name: attrs.name || null,
      sent_at: sentAt,
      sent_day_of_week: dow,
      sent_hour: hour,
      recipients: stats.recipients != null ? Number(stats.recipients) : null,
      opens: stats.opens_unique != null ? Number(stats.opens_unique) : (stats.opens != null ? Number(stats.opens) : null),
      open_rate: stats.open_rate != null ? Number(stats.open_rate) : null,
      clicks: stats.clicks_unique != null ? Number(stats.clicks_unique) : (stats.clicks != null ? Number(stats.clicks) : null),
      click_rate: stats.click_rate != null ? Number(stats.click_rate) : null,
      conversions: stats.conversion_uniques != null ? Number(stats.conversion_uniques) : (stats.conversions != null ? Number(stats.conversions) : null),
      revenue: stats.conversion_value != null ? Math.round(Number(stats.conversion_value)) : (stats.revenue != null ? Math.round(Number(stats.revenue)) : null),
      unsubscribes: stats.unsubscribes != null ? Number(stats.unsubscribes) : null,
      inserted_at: now
    });
  }
}

return rows.map((json) => ({ json }));
